1392→      )
1393→      .eq("id", film_id)
1394→      .single();
1395→
1396→    if (filmError || !film) {
1397→      throw new Error("Film not found");
1398→    }
1399→
1400→    if (!film.is_bulk_film) {
1401→      throw new Error("This is not a bulk film");
1402→    }
1403→
1404→    const currentRemainingExposures = film.bulk_remaining_exposures || 0;
1405→    const currentSpooledCassettes = film.spooled_cassettes || 0;
1406→
1407→    if (exposures_to_spool > currentRemainingExposures) {
1408→      throw new Error(
1409→        `Not enough bulk film remaining. Available: ${currentRemainingExposures} exposures, Requested: ${exposures_to_spool} exposures`
1410→      );
1411→    }
1412→
1413→    const newRemainingExposures =
1414→      currentRemainingExposures - exposures_to_spool;
