1417→    // Update film with new remaining exposures and cassette count
1418→    const { error: updateError } = await this.supabase
1419→      .from("films")
1420→      .update({
1421→        bulk_remaining_exposures: newRemainingExposures,
1422→        spooled_cassettes: newSpooledCassettes,
1423→        count: newSpooledCassettes, // For bulk films, count represents spooled cassettes
