1431→    // Record spooling usage
1432→    const { error: usageError } = await this.supabase
1433→      .from("film_usage")
1434→      .insert({
1435→        film_id,
1436→        quantity: cassettes_created,
1437→        usage_note: spool_note,
1438→        usage_type: "spool",
1439→        exposures_used: exposures_to_spool,
1440→      });
