        quantity,
        trips (title),
        films (name, brand)
      `
      )
      .eq("trip_id", trip_id)
      .eq("film_id", film_id)
      .single();

    if (fetchError || !existingReservation) {
      throw new Error("Film reservation not found for this trip");
    }

    // Update the quantity
    const { error: updateError } = await this.supabase
      .from("trip_films")
      .update({ quantity })
      .eq("trip_id", trip_id)
      .eq("film_id", film_id);

